// OrderList.js
import React, { useState,useCallback, useEffect } from 'react';

const OrderList = ({ apiBaseUrl }) => {
  const [orders, setOrders] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        'Authorization': `Bearer ${authToken}`,
        'Content-Type': 'application/json',
      },
    });
    if (!response.ok) {
        const errorResponse = await response.json();
        console.error('API Error:', errorResponse);
        throw new Error(errorResponse.message || `Error fetching ${url}`);
      }
    return response.json();
  }, []);




  useEffect(() => {
    const fetchOrders = async () => {
      try {
        const response = await fetchAPI(`${apiBaseUrl}/order_listAPI`);
        if (!response.ok) {
          throw new Error('Error fetching orders');
        }
        setOrders(response);
      } catch (error) {
        setError(error.message);
      } finally {
        setIsLoading(false);
      }
    };

    fetchOrders();
  }, [apiBaseUrl, fetchAPI]);
  
  console.log(orders);

  if (isLoading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;

  return (
    <div>
      <h2>Orders</h2>
      <table>
      <thead>
  <tr>
    <th>Order ID</th>
    <th>Location ID</th>
    <th>Material ID</th>
    <th>Vendor ID</th>
    <th>Quantity</th>
    <th>Comments</th>
    <th>Status</th>
    {/* Add more headers if there are more columns */}
  </tr>
</thead>
<tbody>
  {orders.map((order, index) => (
    <tr key={index}>
      <td>{order.order_list_id}</td> {/* Assuming you have an order_list_id field */}
      <td>{order.location_id}</td>
      <td>{order.material_id}</td>
      <td>{order.vendor_id}</td>
      <td>{order.quantity}</td>
      <td>{order.comments}</td>
      <td>{order.status}</td>
      {/* Render more data cells if there are more columns */}
    </tr>
  ))}
</tbody>
      </table>
    </div>
  );
};

export default OrderList;
